// Validate config, stash for downstream nodes.
const relayName = env.get('relay_name');
const outputChip = Number(env.get('output_chip'));
const outputPin = Number(env.get('output_pin'));
const inputChip = Number(env.get('input_chip'));
const inputPin = Number(env.get('input_pin'));
const settleMs = Number(env.get('settle_time_ms')) || 10;
const helperPath = env.get('helper_path');

if (!helperPath) {
    node.error('helper_path env var must be set', msg);
    return null;
}
if (isNaN(outputChip) || outputChip < 0 || outputChip > 7 ||
    isNaN(inputChip) || inputChip < 0 || inputChip > 7) {
    node.error('chip address must be 0-7', msg);
    return null;
}
if (isNaN(outputPin) || outputPin < 0 || outputPin > 15 ||
    isNaN(inputPin) || inputPin < 0 || inputPin > 15) {
    node.error('pin must be 0-15', msg);
    return null;
}

msg._cfg = { relayName, outputChip, outputPin, inputChip, inputPin, settleMs, helperPath };
msg.payload = `python3 ${helperPath} write --chip ${outputChip} --pin ${outputPin} --value 1`;
return msg;

// Parse JSON result from helper. Store commanded value.
try {
    const result = JSON.parse(msg.payload);
    if (!result.success) {
        node.error(`Drive ON failed: ${result.error}`, msg);
        return null;
    }
    msg._on_commanded = 1;
} catch (e) {
    node.error(`Could not parse ON write result: ${msg.payload}`, msg);
    return null;
}
return msg;

const cfg = msg._cfg;
msg.payload = `python3 ${cfg.helperPath} read --chip ${cfg.inputChip} --pin ${cfg.inputPin}`;
return msg;

try {
    const result = JSON.parse(msg.payload);
    if (!result.success) {
        node.error(`Read ON failed: ${result.error}`, msg);
        return null;
    }
    msg._on_check = {
        commanded: msg._on_commanded,
        actual: result.actual,
        ok: msg._on_commanded === result.actual
    };
    delete msg._on_commanded;
} catch (e) {
    node.error(`Could not parse ON read: ${msg.payload}`, msg);
    return null;
}
// Now build the OFF write command.
const cfg = msg._cfg;
msg.payload = `python3 ${cfg.helperPath} write --chip ${cfg.outputChip} --pin ${cfg.outputPin} --value 0`;
return msg;

try {
    const result = JSON.parse(msg.payload);
    if (!result.success) {
        node.error(`Drive OFF failed: ${result.error}`, msg);
        return null;
    }
    msg._off_commanded = 0;
} catch (e) {
    node.error(`Could not parse OFF write: ${msg.payload}`, msg);
    return null;
}
return msg;

const cfg = msg._cfg;
msg.payload = `python3 ${cfg.helperPath} read --chip ${cfg.inputChip} --pin ${cfg.inputPin}`;
return msg;

// Parse the final OFF read and combine everything.
const cfg = msg._cfg;
let offCheck;
try {
    const result = JSON.parse(msg.payload);
    if (!result.success) {
        node.error(`Read OFF failed: ${result.error}`, msg);
        return null;
    }
    offCheck = {
        commanded: msg._off_commanded,
        actual: result.actual,
        ok: msg._off_commanded === result.actual
    };
} catch (e) {
    node.error(`Could not parse OFF read: ${msg.payload}`, msg);
    return null;
}

const onCheck = msg._on_check;
const status = (onCheck.ok && offCheck.ok) ? 'PASS' : 'FAIL';

msg.payload = {
    relay_name: cfg.relayName,
    status: status,
    on_check: onCheck,
    off_check: offCheck,
    timestamp: new Date().toISOString()
};

delete msg._cfg;
delete msg._on_check;
delete msg._off_commanded;

return msg;
